def csv_row_count(path_like: Any) -> int:
    if not path_like:
        return 0
    path = Path(str(path_like))
    if not path.exists():
        return 0
    try:
        df = pd.read_csv(path)
    except Exception:
        return 0
    return int(len(df.index))


def init_signal_frame(df: pd.DataFrame | None = None) -> pd.DataFrame:
    out = df.copy() if isinstance(df, pd.DataFrame) else pd.DataFrame()
    for col in STANDARD_SIGNAL_COLUMNS:
        if col not in out.columns:
            out[col] = ""
    return out[STANDARD_SIGNAL_COLUMNS].copy()


def load_profile_live_candidate_settings(live_cfg: dict[str, Any]) -> dict[str, Any]:
    block = live_cfg.get("smallcap_live_candidates", {}) or {}
    if not isinstance(block, dict) or not block:
        return {}
    settings = dict(DEFAULT_PROFILE_LIVE_CANDIDATE_SETTINGS)
    settings.update({k: v for k, v in block.items() if v not in ("", None)})
    config_value = str(settings.get("config", "")).strip()
    if not config_value:
        return {}
    config_path = Path(config_value)
    if not config_path.is_absolute():
        config_path = (PROJECT_ROOT / config_path).resolve()
    settings["config"] = str(config_path)
    return settings


def compose_profile_merged_signals(
    *,
    base_merged_signals_path: Path,
    profile_buy_signals_path: Path,
    output_path: Path,
    score_floor: float | None,
) -> dict[str, Any]:
    base_df = init_signal_frame(pd.read_csv(base_merged_signals_path)) if base_merged_signals_path.exists() else init_signal_frame()
    profile_buy_df = init_signal_frame(pd.read_csv(profile_buy_signals_path)) if profile_buy_signals_path.exists() else init_signal_frame()

    base_non_buy_df = base_df[base_df["signal_type"].astype(str).str.upper() != "BUY"].copy()
    profile_buy_df = profile_buy_df[profile_buy_df["signal_type"].astype(str).str.upper() == "BUY"].copy()
    raw_profile_buy_rows = int(len(profile_buy_df.index))
    applied_score_floor = parse_optional_float(score_floor)
    if applied_score_floor is not None and not profile_buy_df.empty:
        score_series = pd.to_numeric(profile_buy_df["score"], errors="coerce").fillna(0.0)
        profile_buy_df = profile_buy_df.loc[score_series >= applied_score_floor].copy()

    out_df = init_signal_frame(pd.concat([base_non_buy_df, profile_buy_df], ignore_index=True))
    if not out_df.empty:
        out_df = out_df.sort_values(["signal_type", "ts_code", "strategy_id"], kind="stable").reset_index(drop=True)

    output_path.parent.mkdir(parents=True, exist_ok=True)
    out_df.to_csv(output_path, index=False, encoding="utf-8")
    return {
        "base_non_buy_rows": int(len(base_non_buy_df.index)),
        "raw_profile_buy_rows": raw_profile_buy_rows,
        "filtered_profile_buy_rows": int(len(profile_buy_df.index)),
        "score_floor": applied_score_floor,
        "score_floor_dropped_rows": int(raw_profile_buy_rows - len(profile_buy_df.index)),
        "merged_rows": int(len(out_df.index)),
        "output": str(output_path),
    }


def materialize_profile_candidate_source(
    *,
    live_cfg: dict[str, Any],
    profile_slug: str,
    date_tag: str,
    base_merged_signals_path: Path,
    artifacts: dict[str, Path],
) -> dict[str, Any]:
    settings = load_profile_live_candidate_settings(live_cfg)
    if not settings:
        return {
            "enabled": False,
            "merged_signals": str(base_merged_signals_path),
            "base_merged_signals": str(base_merged_signals_path),
            "reason": "smallcap_live_candidates_missing",
        }

    trade_date = tag_to_iso(date_tag)
    commands: list[dict[str, Any]] = []
    candidate_cmd = [
        "python3",
        "scripts/generate_live_smallcap_candidates.py",
        "--date",
        date_tag,
        "--config",
        str(settings["config"]),
        "--main-count",
        str(settings["main_count"]),
        "--guard-count",
        str(settings["guard_count"]),
        "--main-target-weight",
        str(settings["main_target_weight"]),
        "--guard-target-weight",
        str(settings["guard_target_weight"]),
        "--main-output",
        str(artifacts["candidate_main"]),
        "--guard-output",
        str(artifacts["candidate_guard"]),
        "--summary-output",
        str(artifacts["candidate_summary"]),
        "--overwrite",
    ]
    candidate_out = run_cmd(candidate_cmd)
    commands.append({"step": "generate_live_candidates", **candidate_out})

    raw_specs = [
        (artifacts["candidate_main"], artifacts["signal_raw_main"], "scripts/export_smallcap_v4_2_signal.py"),
        (artifacts["candidate_guard"], artifacts["signal_raw_guard"], "scripts/export_smallcap_v4_2b_signal.py"),
    ]
    raw_paths: list[Path] = []
    for candidate_path, output_path, script_rel in raw_specs:
        if csv_row_count(candidate_path) <= 0:
            continue
        export_cmd = [
            "python3",
            script_rel,
            "--input",
            str(candidate_path),
            "--trade-date",
            trade_date,
            "--output",
            str(output_path),
        ]
        export_out = run_cmd(export_cmd)
        commands.append({"step": "export_signal", **export_out, "candidate": str(candidate_path), "output": str(output_path)})
        raw_paths.append(output_path)

    if raw_paths:
        merge_cmd = [
            "python3",
            "scripts/merge_signals.py",
            "--inputs",
            *[str(path) for path in raw_paths],
            "--output",
            str(artifacts["merged_profile_buys"]),
        ]
        merge_out = run_cmd(merge_cmd)
        commands.append({"step": "merge_signals", **merge_out, "output": str(artifacts["merged_profile_buys"])})
    else:
        empty_df = init_signal_frame()
        artifacts["merged_profile_buys"].parent.mkdir(parents=True, exist_ok=True)
        empty_df.to_csv(artifacts["merged_profile_buys"], index=False, encoding="utf-8")

    score_floor = parse_optional_float(((live_cfg.get("execution_decision") or {}).get("buy_signal_score_floor")))
    merge_summary = compose_profile_merged_signals(
        base_merged_signals_path=base_merged_signals_path,
        profile_buy_signals_path=artifacts["merged_profile_buys"],
        output_path=artifacts["merged_signals_profiled"],
        score_floor=score_floor,
    )
    summary = {
        "enabled": True,
        "profile_slug": profile_slug,
        "date_tag": date_tag,
        "base_merged_signals": str(base_merged_signals_path),
        "merged_signals": str(artifacts["merged_signals_profiled"]),
        "profile_buy_signals": str(artifacts["merged_profile_buys"]),
        "candidate_main": str(artifacts["candidate_main"]),
        "candidate_guard": str(artifacts["candidate_guard"]),
        "candidate_main_rows": csv_row_count(artifacts["candidate_main"]),
        "candidate_guard_rows": csv_row_count(artifacts["candidate_guard"]),
        "live_candidate_settings": settings,
        "score_floor": score_floor,
        "commands": commands,
        "merge_summary": merge_summary,
        "summary_file": str(artifacts["candidate_summary"]),
    }
    artifacts["candidate_summary"].parent.mkdir(parents=True, exist_ok=True)
    artifacts["candidate_summary"].write_text(json.dumps(summary, ensure_ascii=False, indent=2), encoding="utf-8")
    return summary


def build_order_diagnostics(
    *,
    profile_slug: str,
    date_tag: str,
    signal_materialization: dict[str, Any],
    stats: dict[str, Any],
    rows: list[dict[str, Any]],
    runtime: Any,
    state: dict[str, Any],
) -> dict[str, Any]:
    candidate_orders_path = str(signal_materialization.get("candidate_orders") or "").strip()
    candidate_approved_path = str(signal_materialization.get("candidate_approved") or "").strip()
    candidate_tickets_path = str(signal_materialization.get("candidate_tickets") or "").strip()
    candidate_order_rows = csv_row_count(candidate_orders_path)
    candidate_approved_rows = csv_row_count(candidate_approved_path)
    candidate_ticket_rows = csv_row_count(candidate_tickets_path)
    executable_rows = [
        row for row in rows
        if str(row.get("risk_gate", "")).strip().lower() != "blocked"
        and parse_int(row.get("suggest_qty"), 0) > 0
    ]
    executable_buy_rows = [
        row for row in executable_rows if str(row.get("side", "")).strip().upper() == "BUY"
    ]
    executable_sell_rows = [
        row for row in executable_rows if str(row.get("side", "")).strip().upper() == "SELL"
    ]

    blocked_buy_total = sum(
        int(parse_float(stats.get(key), 0.0))
        for key in [
            "blocked_buy_halt",
            "blocked_buy_no_price",
            "blocked_buy_intraday_drop",
            "blocked_buy_intraday_chase",
            "blocked_buy_ai_overlay",
            "blocked_buy_budget_cap",
            "blocked_buy_lot",
            "blocked_buy_liquidity",
        ]
    )
    buy_count = int(parse_float(stats.get("buy_count"), 0.0))
    sell_count = int(parse_float(stats.get("sell_count"), 0.0))
    pending_raw = int(parse_float(stats.get("pending_raw"), 0.0))
    pending_after_gate = int(parse_float(stats.get("pending_after_gate"), 0.0))
    pending_netted = int(parse_float(stats.get("pending_netted"), 0.0))
    decision_eligible_buy_count = int(parse_float(stats.get("decision_eligible_buy_count"), 0.0))
    buy_budget_slots = int(parse_float(stats.get("buy_budget_slots"), 0.0))

    root_cause = "buy_candidates_ready"
    if candidate_ticket_rows <= 0:
        if candidate_order_rows <= 0:
            root_cause = "no_candidate_orders"
            if candidate_approved_rows <= 0:
                root_cause = "no_approved_signals"
        else:
            root_cause = "ticket_builder_zero_rows"
    elif pending_raw <= 0:
        root_cause = "no_pending_tickets"
    elif pending_after_gate <= 0 and pending_raw > 0:
        root_cause = "all_filtered_pre_gate"
    elif pending_netted <= 0 and pending_after_gate > 0:
        root_cause = "all_removed_after_netting"
    elif buy_count <= 0:
        root_cause = "sell_only_no_buy_candidates" if sell_count > 0 else "no_buy_candidates"
    elif decision_eligible_buy_count <= 0:
        if int(parse_float(stats.get("blocked_buy_halt"), 0.0)) >= buy_count:
            root_cause = "all_blocked_by_runtime_gate"
        elif blocked_buy_total >= buy_count:
            root_cause = "all_blocked_by_buy_filters"
        else:
            root_cause = "all_buy_candidates_blocked"
    elif buy_budget_slots <= 0:
        root_cause = "budget_slots_zero"
    elif not executable_buy_rows:
        root_cause = "sell_only_after_filters" if executable_sell_rows else "buy_zero_after_sizing"

    diagnostics = {
        "date_tag": date_tag,
        "profile_slug": profile_slug,
        "root_cause": root_cause,
        "summary": {
            "candidate_approved_rows": candidate_approved_rows,
            "candidate_order_rows": candidate_order_rows,
            "candidate_ticket_rows": candidate_ticket_rows,
            "pending_raw": pending_raw,
            "pending_after_gate": pending_after_gate,
            "pending_netted": pending_netted,
            "buy_count": buy_count,
            "sell_count": sell_count,
            "decision_eligible_buy_count": decision_eligible_buy_count,
            "buy_budget_slots": buy_budget_slots,
            "executable_order_rows": len(executable_rows),
            "executable_buy_rows": len(executable_buy_rows),
            "executable_sell_rows": len(executable_sell_rows),
            "blocked_buy_total": blocked_buy_total,
            "blocked_sell_no_holding": int(parse_float(stats.get("blocked_sell_no_holding"), 0.0)),
        },
        "blocked_breakdown": {
            "blocked_buy_halt": int(parse_float(stats.get("blocked_buy_halt"), 0.0)),
            "blocked_buy_no_price": int(parse_float(stats.get("blocked_buy_no_price"), 0.0)),
            "blocked_buy_intraday_drop": int(parse_float(stats.get("blocked_buy_intraday_drop"), 0.0)),
            "blocked_buy_intraday_chase": int(parse_float(stats.get("blocked_buy_intraday_chase"), 0.0)),
            "blocked_buy_ai_overlay": int(parse_float(stats.get("blocked_buy_ai_overlay"), 0.0)),
            "blocked_buy_budget_cap": int(parse_float(stats.get("blocked_buy_budget_cap"), 0.0)),
            "blocked_buy_lot": int(parse_float(stats.get("blocked_buy_lot"), 0.0)),
            "blocked_buy_liquidity": int(parse_float(stats.get("blocked_buy_liquidity"), 0.0)),
            "blocked_pre": int(parse_float(stats.get("blocked_pre"), 0.0)),
        },
        "runtime": {
            "mode": str(getattr(runtime, "mode", "") or ""),
            "risk_off": bool(getattr(runtime, "risk_off", False)),
            "hard_stop": bool(getattr(runtime, "hard_stop", False)),
            "halt_new_buy": bool(getattr(runtime, "halt_new_buy", False)),
            "halt_reason": str(getattr(runtime, "halt_reason", "") or ""),
            "gate_reasons": list(getattr(runtime, "gate_reasons", []) or []),
            "market_breadth": state.get("market_breadth"),
        },
        "signal_materialization": {
            "source": signal_materialization.get("source"),
            "merged_signals": signal_materialization.get("merged_signals"),
            "candidate_approved": candidate_approved_path,
            "candidate_orders": candidate_orders_path,
            "candidate_tickets": candidate_tickets_path,
            "ticket_rows": signal_materialization.get("ticket_rows"),
        },
        "files": {
            "candidate_approved": candidate_approved_path,
            "candidate_orders": candidate_orders_path,
            "candidate_tickets": candidate_tickets_path,
        },
    }
    return diagnostics


